#include <bits/stdc++.h>
using namespace std;
struct Str{
    int big,dq;
    vector<string> m;
};
map<string,Str> kind;
int n;
int main(){
    Str temp;
    temp.big=temp.dq=1;
    kind["byte"]=temp;
    temp.big=temp.dq=2;
    kind["short"]=temp;
    temp.big=temp.dq=4;
    kind["int"]=temp;
    temp.big=temp.dq=8;
    kind["long"]=temp;
    cin>>n;
    while(n--){
        int op;
        cin>>op;
        if(op==1){
            string s;
            int k;
            Str tmp;
            tmp.dq=0;
            cin>>s>>k;
            for(int i=1;i<=k;i++){
                string a,b;
                cin>>a>>b;
                tmp.m.push_back(b);
                tmp.dq=max(tmp.dq,kind[a].big);
            }
            tmp.big=tmp.dq*k;
            kind[s]=tmp;
            cout<<kind[s].big<<' '<<kind[s].dq<<endl;
        }
    }
    return 0;
}
